mapper.select:
SELECT c.id AS customerId, t.id AS thirdPartyId
    FROM tb_customer AS c
LEFT JOIN tb_customer_third_party AS t
    ON t.customer_id = c.id
    AND t.platform  = #{platform}
WHERE c.tel = #{phoneNum};

mapper.insert:
insert into tb_customer_third_party (
    customer_id,
    platform,
    open_id
     , nickname 
     , avatar 
     , remark 
)
values (
    #{customerId},
    #{platform},
    #{openId}
     , #{nickname} 
     , #{avatar} 
     , #{remark} 
)
